        $report | Should -Match 'CPU Threshold:\s+50'
        $report | Should -Match 'Memory Threshold:\s+1000'
        $report | Should -Match 'dbserv'
        $report | Should -Match 'browser'
        $report | Should -Match '400'   # PID
